import api from './api';

export default {
  /**
   * Login user
   * @param {Object} credentials - User credentials (username, password)
   * @returns {Promise} Promise containing the authentication result
   */
  login(credentials) {
    return api.post('/auth/signin', credentials)
      .then(response => {
        // 处理登录响应，标准化token格式
        const userData = {
          ...response.data,
          token: response.data.token || response.data.accessToken
        };
        
        // 存储用户信息到本地存储
        localStorage.setItem('user', JSON.stringify(userData));
        
        return userData;
      });
  },
  
  /**
   * Register new user
   * @param {Object} userData - User registration data
   * @returns {Promise} Promise containing the registration result
   */
  register(userData) {
    return api.post('/auth/signup', userData);
  },
  
  /**
   * Check auth status
   * @returns {Promise} Promise containing the auth status
   */
  checkAuthStatus() {
    return api.get('/auth/check');
  },
  
  /**
   * Save user data to local storage
   * @param {Object} userData - User data to save
   */
  saveUser(userData) {
    localStorage.setItem('user', JSON.stringify(userData));
  },
  
  /**
   * Get user data from local storage
   * @returns {Object|null} User data or null if not found
   */
  getUser() {
    const userStr = localStorage.getItem('user');
    if (!userStr) {
      return null;
    }
    
    try {
      return JSON.parse(userStr);
    } catch (e) {
      console.error('解析用户信息失败:', e);
      return null;
    }
  },
  
  /**
   * Remove user data from local storage (logout)
   */
  logout() {
    localStorage.removeItem('user');
  },
  
  /**
   * Check if user has a specific role
   * @param {string} roleName - Role name to check
   * @returns {boolean} True if user has the role
   */
  hasRole(roleName) {
    const user = this.getUser();
    if (!user || !user.roles) {
      return false;
    }
    
    // 处理角色可能是数组或字符串的情况
    if (Array.isArray(user.roles)) {
      return user.roles.includes(roleName);
    } else if (typeof user.roles === 'string') {
      return user.roles === roleName;
    }
    
    return false;
  },
  
  /**
   * Check if user is admin
   * @returns {boolean} True if user is admin
   */
  isAdmin() {
    return this.hasRole('ROLE_ADMIN');
  }
};
